import {
  HAIKU_PROVIDER_ID,
  PRIMARY_PROVIDER_ID,
  type AgentTaskKind,
  type AgentTaskProfileOverride,
  type ProviderId,
} from '../../shared/types/model';
import { buildTaskProfile } from './taskProfile';

const DEFAULT_PROVIDER_ORDER: ProviderId[] = [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID];

export type PrimaryProviderBackend = 'exec' | 'app-server';

export type ProviderRoutingCapabilities = Partial<Record<ProviderId, {
  supportsV2ToolRuntime: boolean;
}>>;

export function taskKindRequiresV2ToolRuntime(kind: AgentTaskKind): boolean {
  return kind === 'orchestration'
    || kind === 'research'
    || kind === 'browser-automation'
    || kind === 'implementation'
    || kind === 'debug'
    || kind === 'review';
}

export function shouldPreferExecForTaskKind(taskKind: AgentTaskKind): boolean {
  return taskKind === 'implementation' || taskKind === 'debug' || taskKind === 'review';
}

export function resolvePrimaryProviderBackend(
  taskKind: AgentTaskKind,
  configuredMode = process.env.CODEX_PROVIDER,
  execAvailable = true,
): PrimaryProviderBackend {
  if (!execAvailable) return 'app-server';
  if (configuredMode === 'exec') return 'exec';
  return shouldPreferExecForTaskKind(taskKind) ? 'exec' : 'app-server';
}

export function providerSupportsPrompt(
  providerId: ProviderId,
  prompt: string,
  overrides?: AgentTaskProfileOverride,
  capabilities?: ProviderRoutingCapabilities,
): boolean {
  const profile = buildTaskProfile(prompt, overrides);
  if (!taskKindRequiresV2ToolRuntime(profile.kind)) return true;
  if (!capabilities) return true;
  return capabilities[providerId]?.supportsV2ToolRuntime === true;
}

export function pickProviderForPrompt(
  prompt: string,
  availableProviders: Iterable<ProviderId>,
  overrides?: AgentTaskProfileOverride,
  capabilities?: ProviderRoutingCapabilities,
): ProviderId | null {
  const available = new Set(
    Array.from(availableProviders).filter((providerId) => providerSupportsPrompt(
      providerId,
      prompt,
      overrides,
      capabilities,
    )),
  );
  const profile = buildTaskProfile(prompt, overrides);

  if (available.size === 0) return null;

  if (profile.kind === 'research') {
    if (available.has(HAIKU_PROVIDER_ID)) return HAIKU_PROVIDER_ID;
    if (available.has(PRIMARY_PROVIDER_ID)) return PRIMARY_PROVIDER_ID;
  }

  if (profile.kind === 'browser-automation') {
    if (available.has(PRIMARY_PROVIDER_ID)) return PRIMARY_PROVIDER_ID;
    if (available.has(HAIKU_PROVIDER_ID)) return HAIKU_PROVIDER_ID;
  }

  if (profile.kind === 'implementation') {
    if (available.has(PRIMARY_PROVIDER_ID)) return PRIMARY_PROVIDER_ID;
    if (available.has(HAIKU_PROVIDER_ID)) return HAIKU_PROVIDER_ID;
  }

  if (
    profile.kind === 'orchestration'
    || profile.kind === 'review'
    || profile.kind === 'debug'
  ) {
    if (available.has(PRIMARY_PROVIDER_ID)) return PRIMARY_PROVIDER_ID;
    if (available.has(HAIKU_PROVIDER_ID)) return HAIKU_PROVIDER_ID;
  }

  for (const providerId of DEFAULT_PROVIDER_ORDER) {
    if (available.has(providerId)) return providerId;
  }

  return null;
}

import { describe, expect, it } from 'vitest';
import { pickProviderForPrompt } from './providerRouting';
import { HAIKU_PROVIDER_ID, PRIMARY_PROVIDER_ID } from '../../shared/types/model';

describe('provider routing', () => {
  const capabilities = {
    [PRIMARY_PROVIDER_ID]: { supportsV2ToolRuntime: true },
    [HAIKU_PROVIDER_ID]: { supportsV2ToolRuntime: true },
  } as const;

  it('prefers haiku for research tasks when available', () => {
    expect(pickProviderForPrompt('Search online for the latest SEC guidance', [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID], undefined, capabilities))
      .toBe(HAIKU_PROVIDER_ID);
  });

  it('routes implementation, debug, and review tasks to gpt-5.4 when available', () => {
    expect(pickProviderForPrompt('Patch this TypeScript file and run the local build', [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID], undefined, capabilities))
      .toBe(PRIMARY_PROVIDER_ID);
    expect(pickProviderForPrompt('Debug why the Electron app crashes on startup', [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID], undefined, capabilities))
      .toBe(PRIMARY_PROVIDER_ID);
    expect(pickProviderForPrompt('Review this PR diff and call out regressions', [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID], undefined, capabilities))
      .toBe(PRIMARY_PROVIDER_ID);
  });

  it('falls back to the remaining available provider', () => {
    expect(pickProviderForPrompt('Search for the latest Electron release notes', [PRIMARY_PROVIDER_ID], undefined, capabilities))
      .toBe(PRIMARY_PROVIDER_ID);
    expect(pickProviderForPrompt('Help me think through a product naming idea', [HAIKU_PROVIDER_ID], undefined, capabilities))
      .toBe(HAIKU_PROVIDER_ID);
    expect(pickProviderForPrompt('Search online for the latest Electron release notes', [HAIKU_PROVIDER_ID], undefined, capabilities))
      .toBe(HAIKU_PROVIDER_ID);
  });

  it('routes repo-wide planning to gpt-5.4 and CI investigation to the debug path', () => {
    expect(pickProviderForPrompt('Plan a repo-wide migration strategy', [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID], undefined, capabilities))
      .toBe(PRIMARY_PROVIDER_ID);
    expect(pickProviderForPrompt('Investigate the failing CI and explain root cause', [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID], undefined, capabilities))
      .toBe(PRIMARY_PROVIDER_ID);
  });

  it('uses explicit task kind overrides ahead of prompt heuristics', () => {
    expect(pickProviderForPrompt(
      'Help me think through a product naming idea',
      [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID],
      { kind: 'implementation' },
      capabilities,
    )).toBe(PRIMARY_PROVIDER_ID);

    expect(pickProviderForPrompt(
      'Patch this TypeScript file and run the local build',
      [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID],
      { kind: 'research' },
      capabilities,
    )).toBe(HAIKU_PROVIDER_ID);
  });
});

// ═══════════════════════════════════════════════════════════════════════════
// Model Layer Types — Provider registry, routing, handoff, Codex events
// ═══════════════════════════════════════════════════════════════════════════

// ─── Provider Identity ────────────────────────────────────────────────────

export const PRIMARY_PROVIDER_ID = 'gpt-5.4' as const;
export const HAIKU_PROVIDER_ID = 'haiku' as const;
export const PROVIDER_IDS = [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID] as const;

export type ProviderId = typeof PROVIDER_IDS[number];
export type LegacyProviderId = 'codex';
export type AnyProviderId = ProviderId | LegacyProviderId;

export type ProviderKind = 'cli-process' | 'api-streaming';

export type ProviderStatus = 'available' | 'unavailable' | 'busy' | 'error';

export type ProviderCapability =
  | 'code-generation'
  | 'code-editing'
  | 'shell-execution'
  | 'repo-analysis'
  | 'chat'
  | 'summarization'
  | 'intent-parsing'
  | 'plan'
  | 'planning'
  | 'synthesis';

// ─── Provider Definition (static, configured at startup) ──────────────────

export type ProviderDefinition = {
  id: ProviderId;
  displayName: string;
  kind: ProviderKind;
  capabilities: ProviderCapability[];
};

// ─── Provider Metrics (from Codex /status) ────────────────────────────────

export type CodexStatusMetrics = {
  contextWindow?: { percentLeft: number; used: string; total: string };
  limit5h?: { percentLeft: number; resetsAt: string };
  limitWeekly?: { percentLeft: number; resetsAt: string };
  credits?: number;
};

// ─── Provider Runtime (dynamic, changes per-request) ──────────────────────

export type ProviderRuntime = {
  id: ProviderId;
  status: ProviderStatus;
  activeTaskId: string | null;
  lastActivityAt: number | null;
  errorDetail: string | null;
  sessionId?: string;
  model?: string;
  metrics?: CodexStatusMetrics;
};

export function createDefaultProviderRuntime(id: ProviderId): ProviderRuntime {
  return {
    id,
    status: 'unavailable',
    activeTaskId: null,
    lastActivityAt: null,
    errorDetail: null,
  };
}

export function isProviderId(value: string): value is ProviderId {
  return value === PRIMARY_PROVIDER_ID || value === HAIKU_PROVIDER_ID;
}

export function isLegacyProviderId(value: string): value is LegacyProviderId {
  return value === 'codex';
}

// ─── Task Ownership ───────────────────────────────────────────────────────

export type ModelOwner = ProviderId | 'user';

export type AgentTaskKind =
  | 'orchestration'
  | 'research'
  | 'browser-automation'
  | 'implementation'
  | 'debug'
  | 'review'
  | 'delegation'
  | 'browser-search'
  | 'local-code'
  | 'general';

export const AGENT_TOOL_PACK_PRESETS = ['all', 'mode-6', 'mode-4'] as const;
export type AgentToolPackPreset = typeof AGENT_TOOL_PACK_PRESETS[number];

export type AgentTaskProfileOverride = {
  kind?: AgentTaskKind;
  skillNames?: string[];
  toolPackPreset?: AgentToolPackPreset;
  canSpawnSubagents?: boolean;
  maxToolTurns?: number;
  requiresBrowserSearchDirective?: boolean;
};

export type ImageInvocationAttachment = {
  type: 'image';
  mediaType: 'image/jpeg' | 'image/png' | 'image/gif' | 'image/webp';
  /** Base64-encoded image data (no data-URL prefix). */
  data: string;
  name?: string;
  /** Optional local filesystem path for providers that can read images directly from disk. */
  path?: string;
};

export type InvocationAttachment = ImageInvocationAttachment | DocumentInvocationAttachment;

export type AgentInvocationOptions = {

