function toolCall(toolName: AgentToolCallRecord['toolName'], startedAt = 1): AgentToolCallRecord {
  return {
    id: `tool-${toolName}-${startedAt}`,
    runId: 'run-1',
    agentId: 'gpt-5.4',
    toolName,
    input: {},
    output: {},
    status: 'completed',
    startedAt,
    completedAt: startedAt + 1,
    error: null,
  };
}

